**Reversing a Linked List in C++**
=====================================

Here's a step-by-step guide on how to reverse a linked list in C++.

**Method 1: Recursive Approach**
--------------------------------

```cpp
// Node structure
struct Node {
    int data;
    Node* next;
};

// Function to reverse the linked list
Node* reverseLinkedList(Node* head) {
    // Base case: if the list is empty or contains only one node
    if (head == nullptr || head->next == nullptr) {
        return head;
    }

    // Recursive case: reverse the rest of the list
    Node* newHead = reverseLinkedList(head->next);

    // Reverse the link between the current node and the next node
    head->next->next = head;
    head->next = nullptr;

    // Return the new head of the reversed list
    return newHead;
}
```

**Method 2: Iterative Approach**
-------------------------------

```cpp
// Function to reverse the linked list
Node* reverseLinkedList(Node* head) {
    Node* prev = nullptr;
    Node* curr = head;
    Node* next = nullptr;

    while (curr != nullptr) {
        // Store the next node before reversing the link
        next = curr->next;

        // Reverse the link between the current node and the next node
        curr->next = prev;

        // Move to the next node
        prev = curr;
        curr = next;
    }

    // Return the new head of the reversed list
    return prev;
}
```

**Example Use Case**
--------------------

```cpp
int main() {
    // Create a linked list: 1 -> 2 -> 3 -> 4 -> 5
    Node* head = new Node{1};
    head->next = new Node{2};
    head->next->next = new Node{3};
    head->next->next->next = new Node{4};
    head->next->next->next->next = new Node{5};

    // Reverse the linked list
    head = reverseLinkedList(head);

    // Print the reversed linked list
    while (head != nullptr) {
        std::cout << head->data << " ";
        head = head->next;
    }

    return 0;
}
```

